# Inputs:
# - initial_input: The initial input to the prompt chain (string)
# - prompt_output: The output generated by the prompt chain (string)
# - eval_model: The evaluation model to use for computing accuracy (object)

# Output:
# - accuracy_score: A accuracy score between 0 and 100

import re
from Genetic_algorithm_processes.ollama_run import PromptChainRunner


class PromptOutputEval:
    def __init__(self, eval_model: str, runner = PromptChainRunner()):
        """
        Args:
            eval_model: Name of the Ollama model to use for evaluation (e.g. 'qwen:0.5b')
            runner: An initialized PromptChainRunner instance
        """
        self.eval_model = eval_model
        self.runner = runner
        
    def evaluate(self, prompt_output: str, initial_input: str) -> float:
        """
        Evaluates the prompt output against the initial input using the evaluation model.

        Parameters:
        - initial_input: The initial input to the prompt chain (string)
        - prompt_output: The output generated by the prompt chain (string)

        Returns:
        - accuracy_score: A float score between 0 and 100
        """
        eval_prompt = f"""You are an objective evaluator. Score how well the OUTPUT answers or addresses the INPUT on a scale of 0 to 100.

INPUT:
{initial_input}

OUTPUT:
{prompt_output}

Scoring criteria:
- 100: Perfectly addresses the input, accurate and complete
- 75-99: Mostly correct with minor gaps or inaccuracies
- 50-74: Partially addresses the input, missing key aspects
- 25-49: Mostly off-topic or significantly incomplete
- 0-24: Completely irrelevant or incorrect

Respond with ONLY a single integer between 0 and 100. No explanation, no punctuation, just the number."""

        output, _ = self.runner.run_ollama_model(self.eval_model, eval_prompt)

        return self._parse_score(output)

    def _parse_score(self, model_output: str) -> float:
        """
        Parses the model output to extract a numeric score.

        Args:
            model_output: Raw string output from the evaluation model

        Returns:
            A float score between 0 and 100
        """
        match = re.search(r'\b(\d{1,3})\b', model_output.strip())
        if match:
            score = float(match.group(1))
            return max(0.0, min(100.0, score))  # Clamp to [0, 100]

        print(f"Warning: Could not parse score from model output: '{model_output}'")
        return 0.0


# Example usage:
if __name__ == "__main__":
    initial_input = "What is the capital of Russia?"
    prompt_output = "St. Petersburg is the capital city of Russia."

    evaluator = PromptOutputEval(eval_model="gemma3:latest", runner=PromptChainRunner())


    score = evaluator.evaluate(prompt_output, initial_input)
    print(f"Accuracy Score: {score:.1f}/100")